import React, { useState } from 'react';
import { Link } from 'react-router-dom';

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'Electronics', path: '/electronics' },
    { name: 'Electrical', path: '/electrical' },
    { name: 'Chemical', path: '/chemical' },
    { name: 'Industries', path: '/industries' },
    { name: 'About Us', path: '/about' },
    { name: 'Careers', path: '/careers' },
  ];

  return (
    <nav className="bg-white/95 backdrop-blur-md shadow-sm fixed w-full z-50 top-0 left-0 border-b border-gray-100">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-20">

          {/* Logo Section - Reference Style */}
          <div className="flex-shrink-0 flex items-center">
            <Link to="/" className="flex items-center space-x-1">
              <span className="text-3xl font-black text-[#1C1C1C] tracking-tighter">
                HUDSON
              </span>
              <div className="h-2 w-2 rounded-full bg-orange-500 mt-2"></div>
            </Link>
          </div>

          {/* Desktop Menu Items - Adjusted Spacing & Font */}
          <div className="hidden lg:flex items-center space-x-8">
            {navLinks.map((link) => (
              <Link
                key={link.name}
                to={link.path}
                className="text-gray-600 hover:text-orange-600 font-medium text-[15px] transition-all duration-200"
              >
                {link.name}
              </Link>
            ))}
          </div>

          {/* Right Action Buttons - Reference Image Style */}
          <div className="hidden md:flex items-center space-x-4">
            <button className="text-orange-600 font-semibold px-5 py-2 rounded-full border border-orange-100 hover:bg-orange-50 transition-all text-sm">
              Sign In
            </button>
            <button className="bg-gradient-to-r from-orange-500 to-orange-600 text-white px-6 py-2.5 rounded-full font-bold text-sm shadow-md hover:shadow-orange-200 transform hover:-translate-y-0.5 transition-all">
              Contact Us
            </button>
          </div>

          {/* Mobile Menu Button */}
          <div className="lg:hidden flex items-center">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="inline-flex items-center justify-center p-2 rounded-md text-gray-700 hover:text-orange-600 focus:outline-none"
            >
              <svg className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                {isOpen ? (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                ) : (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
                )}
              </svg>
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu Dropdown */}
      {isOpen && (
        <div className="lg:hidden bg-white border-t border-gray-100 shadow-2xl animate-in slide-in-from-top duration-300">
          <div className="px-4 pt-2 pb-6 space-y-2">
            {navLinks.map((link) => (
              <Link
                key={link.name}
                to={link.path}
                onClick={() => setIsOpen(false)}
                className="block px-3 py-4 text-base font-semibold text-gray-800 hover:bg-orange-50 hover:text-orange-600 rounded-xl transition-all"
              >
                {link.name}
              </Link>
            ))}
            <div className="pt-4 grid grid-cols-2 gap-4">
              <button className="text-orange-600 font-bold py-3 border border-orange-100 rounded-xl">
                Sign In
              </button>
              <button className="bg-orange-500 text-white font-bold py-3 rounded-xl shadow-lg shadow-orange-200">
                Contact Us
              </button>
            </div>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
